 width="48"
 height="48"
 aria-hidden="true"
 >
 <path
 d="M24 4C24 4 10 18 10 28a14 14 0 0028 0C38 18 24 4 24 4z"
 fill="#D32F2F"
 />
 <rect x="21" y="20" width="6" height="16" rx="1" fill="#FFF" />
 <rect x="16" y="25" width="16" height="6" rx="1" fill="#FFF" />
 </svg>
 <div className="ll-header__text">
 <h1 className="ll-header__title">LifeLink Blood Donation Network</h1>
 <p className="ll-header__subtitle">
 Saving Lives Through Smart Blood Management
 </p>
 </div>
 </div>
 </header>
 );
}
","import React from "react";
import "./KpiCard.css";

interface KpiCardProps {
 icon: string;
 value: number;
 label: string;
 color: string;
}

export default function KpiCard({ icon, value, label, color }: KpiCardProps) {
 return (
 <div className="ll-kpi-card" style={{ borderLeftColor: color }}>
 <div className="ll-kpi-card__icon">{icon}</div>
 <div className="ll-kpi-card__content">
 <span className="ll-kpi-card__value">{value.toLocaleString()}</span>
 <span className="ll-kpi-card__label">{label}</span>
 </div>
 </div>
 );
}
