",":root {
 --ll-primary: #d32f2f;
 --ll-primary-dark: #c62828;
 --ll-blue: #1976d2;
 --ll-green: #43a047;
 --ll-amber: #fb8c00;
 --ll-bg: #f5f7fa;
 --ll-card: #ffffff;
 --ll-border: #e0e0e0;
 --ll-text: #212121;
 --ll-text-secondary: #616161;
 --ll-font: "Inter", Arial, sans-serif;
}

* {
 box-sizing: border-box;
}

body {
 margin: 0;
 padding: 0;
 background: var(--ll-bg);
 font-family: var(--ll-font);
 color: var(--ll-text);
 -webkit-font-smoothing: antialiased;
}

.ll-app {
 min-height: 100vh;
 display: flex;
 flex-direction: column;
}

.ll-main {
 flex: 1;
 padding: 32px;
 max-width: 1200px;
 margin: 0 auto;
 width: 100%;
}

.ll-section-title {
 margin: 0 0 20px 0;
 font-size: 18px;
 font-weight: 600;
 color: var(--ll-text);
}

.ll-kpi-grid {
 display: grid;
 grid-template-columns: repeat(3, 1fr);
 gap: 20px;
}

.ll-loading {
 display: flex;
 align-items: center;
 justify-content: center;
 padding: 80px 0;
 font-size: 16px;
 color: var(--ll-text-secondary);
